    ? ('upstream_dark_pool_' + _dpRegimeUp.toLowerCase() + (prev.dp_error ? ': ' + prev.dp_error : ''))
    : 'missing_ticker_from_upstream';
  console.error('[CA-ENGINE] FAIL-CLOSED: ' + _reason + ' ticker=' + (prev.ticker || 'UNKNOWN'));
