function extractScoreFromObject(obj) {
  if (!obj || typeof obj !== 'object') return null;
  const candidateKeys = [
    'final_composite_score', 'composite_score', 'vc_composite_score',
    'vc_score', 'live_vc_score', '_vc_score', 'score', 'rating'
