const needsRsi    = !item.rsi    || item.rsi    === 'N/A' || item.rsi    === 0 || item.rsi    === '0';
const needsMacd   = !item.macd_hist || item.macd_hist === 'N/A' || item.macd_hist === 0 || item.macd_hist === '0';
const needsSma50  = !item.sma50  || item.sma50  === 'N/A' || item.sma50  === 0 || item.sma50  === '0';
const needsEma200 = !item.ema200 || item.ema200 === 'N/A' || item.ema200 === 0 || item.ema200 === '0';
const needsVwap   = !item.vwap   || item.vwap   === 'N/A' || item.vwap   === 0 || item.vwap   === '0';

const ticker = item.ticker;
if (!ticker || ticker === 'UNKNOWN') return [{ json: await qtpChartVisionShadow.call(this, item) }];

// If everything is present, pass through immediately — no API calls
if (!needsRsi && !needsMacd && !needsSma50 && !needsEma200 && !needsVwap) {
  console.log('[ENRICH] All indicators present for', ticker, '— pass-through');
  return [{ json: await qtpChartVisionShadow.call(this, item) }];
}

// Determine timespan for RSI/MACD based on signal timeframe
const tf = (item.timeframe || '').toString().toUpperCase();
const isScalp = ['1','1M','3','3M','5','5M','15','15M'].includes(tf);
const indTimespan = isScalp ? 'minute' : 'day';

const enriched = { ...item };

// Helper: safe fetch
async function safeFetch(url) {
  try {
    return await this.helpers.httpRequest({ method: 'GET', url, timeout: 5000 });
  } catch (e) {
    console.error('[ENRICH] Fetch error:', e.message);
    return null;
  }
}

// Fetch RSI (14)
if (needsRsi) {
  const url = `https://api.polygon.io/v1/indicators/rsi/${ticker}?timespan=${indTimespan}&adjusted=true&window=14&series_type=close&order=desc&limit=1&apiKey=${POLYGON_KEY}`;
  const data = await safeFetch.call(this, url);
  const v = data?.results?.values?.[0]?.value;
  if (v !== undefined) enriched.rsi = parseFloat(v).toFixed(2);
  console.log('[ENRICH] RSI', ticker, '=', enriched.rsi);
}

// Fetch MACD histogram (12/26/9)
if (needsMacd) {
  const url = `https://api.polygon.io/v1/indicators/macd/${ticker}?timespan=${indTimespan}&adjusted=true&short_window=12&long_window=26&signal_window=9&series_type=close&order=desc&limit=1&apiKey=${POLYGON_KEY}`;
  const data = await safeFetch.call(this, url);
  const v = data?.results?.values?.[0]?.histogram;
  if (v !== undefined) enriched.macd_hist = parseFloat(v).toFixed(4);
  console.log('[ENRICH] MACD', ticker, '=', enriched.macd_hist);
}

// Fetch SMA50 (daily)
if (needsSma50) {
  const url = `https://api.polygon.io/v1/indicators/sma/${ticker}?timespan=day&adjusted=true&window=50&series_type=close&order=desc&limit=1&apiKey=${POLYGON_KEY}`;
  const data = await safeFetch.call(this, url);
  const v = data?.results?.values?.[0]?.value;
  if (v !== undefined) enriched.sma50 = parseFloat(v).toFixed(2);
  console.log('[ENRICH] SMA50', ticker, '=', enriched.sma50);
}

// Fetch EMA200 (daily)
if (needsEma200) {
  const url = `https://api.polygon.io/v1/indicators/ema/${ticker}?timespan=day&adjusted=true&window=200&series_type=close&order=desc&limit=1&apiKey=${POLYGON_KEY}`;
  const data = await safeFetch.call(this, url);
  const v = data?.results?.values?.[0]?.value;
  if (v !== undefined) enriched.ema200 = parseFloat(v).toFixed(2);
  console.log('[ENRICH] EMA200', ticker, '=', enriched.ema200);
}

// Fetch VWAP (from daily aggregate bar — field is 'vw' in Polygon aggs)
if (needsVwap) {
  const today = new Date().toISOString().split('T')[0];
  const aggUrl = `https://api.polygon.io/v2/aggs/ticker/${ticker}/range/1/day/${today}/${today}?adjusted=true&apiKey=${POLYGON_KEY}`;
  const aggData = await safeFetch.call(this, aggUrl);
  let v = aggData?.results?.[0]?.vw;
  // Fallback: try snapshot endpoint if agg not available yet (pre-market)
  if (!v || v === 0) {
    const snapUrl = `https://api.polygon.io/v2/snapshot/locale/us/markets/stocks/tickers/${ticker}?apiKey=${POLYGON_KEY}`;
    const snapData = await safeFetch.call(this, snapUrl);
    v = snapData?.ticker?.day?.vwap || snapData?.ticker?.min?.av;
  }
  if (v !== undefined && v !== 0) enriched.vwap = parseFloat(v).toFixed(2);
  console.log('[ENRICH] VWAP', ticker, '=', enriched.vwap);
}

enriched._enriched = true;
enriched._enriched_fields = ['rsi','macd','sma50','ema200','vwap'].filter((f,i) => [
  needsRsi && enriched.rsi !== item.rsi,
  needsMacd && enriched.macd_hist !== item.macd_hist,
  needsSma50 && enriched.sma50 !== item.sma50,
  needsEma200 && enriched.ema200 !== item.ema200,
  needsVwap && enriched.vwap !== item.vwap
][i]).join(',');

console.log('[ENRICH] Done for', ticker, '— filled:', enriched._enriched_fields || 'none');
// Fix #17 Batch 2 (hotfix): expose polygon_key to downstream HTTP nodes
enriched._polygon_key = POLYGON_KEY;
return [{ json: await qtpChartVisionShadow.call(this, enriched) }];

// Channel Gate v1.0 — unified subscriber notification gate
// Rules:
//   1. Block empty messages
//   2. Block test_mode signals
//   3. 60-second per-ticker dedup to prevent flood
//   QTP_CHANNEL_GATE_EXEC_META_20260506: recovered execution messages carry ticker metadata and may bypass stale UNKNOWN dedup

const items = $input.all();
const results = [];

for (const item of items) {
  const d = item.json;
  const msg = d.message || d.text || '';

  // Gate 1: no empty messages
  if (!msg || msg.trim().length === 0) continue;

  // Gate 2: block test mode
  if (d.test_mode === true || d.test_mode === 'true') continue;

  // QTP_CHANNEL_GATE_DEDUP_v4.2.5.5
  // 10-minute subscriber dedup for same ticker/action/price. Even recovered broker
  // notifications cannot bypass this if the semantic alert is the same; this stops
  // duplicate VLTO-style messages caused by multi-branch enrichment outputs.
  const ticker = String(d.ticker || d.symbol || 'UNKNOWN').toUpperCase();
  const exec = String(d.execution || d.signal || d.action || 'UNKNOWN').toUpperCase();
  const px = Number(d.price || d.close || d.entry || 0);
  const pxBucket = Number.isFinite(px) ? (Math.round(px * 100) / 100).toFixed(2) : 'NA';
  const now = Date.now();
  const key = `channel_gate_v4255_${ticker}_${exec}_${pxBucket}`;
  const wfStatic = $getWorkflowStaticData('global');
  const lastSent = Number(wfStatic[key] || 0);
  const DEDUP_MS = 10 * 60 * 1000;
  if (now - lastSent < DEDUP_MS) {
    console.log(`[Channel Gate v4.2.5.5] DEDUP ${key}; suppressed duplicate user message`);
    continue;
  }
  wfStatic[key] = now;
  // prune old v4.2.5.5 keys opportunistically
  for (const k of Object.keys(wfStatic)) {
    if (k.startsWith('channel_gate_v4255_') && now - Number(wfStatic[k] || 0) > 30 * 60 * 1000) delete wfStatic[k];
  }
  results.push(item);
}

return results;

const state = $getWorkflowStaticData('global');
state._credentials = state._credentials || {};
state._credentials.webhook_secret = '876a59793c91a728aa6991b72ccc9b7bb872c17d9cda29459d3d3b8c87b3bf7c';
return [{ json: { set: true, len: state._credentials.webhook_secret.length }}];

const creds = $getWorkflowStaticData('global')._credentials || {};
return [{ json: {
  has_webhook_secret: !!creds.webhook_secret,
  length: (creds.webhook_secret || '').length,
  prefix: (creds.webhook_secret || '').slice(0, 8)
}}];

// Weekend Market Guard v1 — blocks all main trading webhook/internal payloads
// on Saturday/Sunday in America/New_York before signal/order processing.
// Health-check workflows remain separate and are not blocked here.
const nyNow = new Date(new Date().toLocaleString('en-US', { timeZone: 'America/New_York' }));
const nyDay = nyNow.getDay(); // 0=Sun, 6=Sat
if (nyDay === 0 || nyDay === 6) {
  return [{
    json: {
      market_open: false,
      blocked: true,
      reason: 'Weekend - US equities market closed',
      action: 'blocked_before_signal_or_order_execution',
      checked_at: new Date().toISOString(),
      checked_timezone: 'America/New_York',
      original_alert_type: $json.alert_type || $json.Alert_Type || null,
      original_ticker: $json.ticker || $json.symbol || $json.Ticker || null,
    }
  }];
}

// Webhook Auth Gate v1 — fail closed on TradingView inputs
// Validates body._secret matches expected webhook secret.
// Internal alert_types (HEARTBEAT, BROAD_SCANNER, REALTIME_AGENT_HYBRID, POLYGON_NEWS)
// bypass the _secret check because they are internal sub-workflow invocations, not TV alerts.
// Throws explicit AUTH_FAILED error on rejection.

const INTERNAL = new Set(['HEARTBEAT','BROAD_SCANNER','REALTIME_AGENT_HYBRID','POLYGON_NEWS']);

// Pull expected secret from workflow staticData; fall back to known documented value so
// a missing staticData entry does not fail-open.
const s = $getWorkflowStaticData('global');
const creds = (s && s._credentials) || {};
const FALLBACK = '6579e4d425aa1a9f4966089b477f6272a6303323a8be24c024d0f71fcb499362';
const expected = creds.webhook_secret || FALLBACK;

const items = $input.all();
const out = [];

// QTP_AUTH_GATE_PROMOTE_ALERT_TYPE_20260507
// After auth succeeds, promote TradingView body fields to top level so downstream
// monitors see alert_type/ticker/execution instead of UNKNOWN. Secrets are removed.
function sanitizeHeaders(h) {
  const out = {...(h || {})};
  for (const k of Object.keys(out)) {
    if (String(k).toLowerCase().includes('secret') || String(k).toLowerCase().includes('authorization')) delete out[k];
  }
  return out;
}
function sanitizeQuery(q) {
  const out = {...(q || {})};
  delete out._secret;
  delete out.secret;
  delete out.passphrase;
  return out;
}
function sanitizeBody(b) {
  const out = {...(b || {})};
  delete out._secret;
  delete out.secret;
  delete out.passphrase;
  return out;
}
function promoteAuthenticatedPayload(item, body, query, headers, alertType, ingressSource) {
  const cleanBody = sanitizeBody(body);
  const cleanQuery = sanitizeQuery(query);
  const cleanHeaders = sanitizeHeaders(headers);
  return {
    json: {
      ...(item.json || {}),
      ...cleanBody,
      body: cleanBody,
      query: cleanQuery,
      headers: cleanHeaders,
      alert_type: alertType,
      _alert_type: alertType,
      _auth_status: 'AUTH_OK',
      _auth_checked_at: new Date().toISOString(),
      _ingress_source: ingressSource,
      source: ingressSource,
      _tv_payload_shape: cleanBody._tv_payload_shape || ((cleanBody.ticker || cleanBody.symbol) ? 'ticker+market_fields' : 'control_or_unknown'),
      _original_alert_type: cleanBody._original_alert_type || alertType
    }
  };
}
for (const item of items) {
  const j = item.json || {};
  // Webhook node exposes body/query/headers. Some internal paths may pass json directly.
  const body = (j.body && typeof j.body === 'object') ? j.body : j;
  const query = (j.query && typeof j.query === 'object') ? j.query : {};
  const headers = (j.headers && typeof j.headers === 'object') ? j.headers : {};
  const headerSecret = headers['x-qtp-signal-secret'] || headers['X-QTP-Signal-Secret'] || headers['x-webhook-secret'] || headers['X-Webhook-Secret'] || headers['X-WEBHOOK-SECRET']; // QTP_HEADER_SIGNAL_SECRET_v4.2.7
  const alertType = String(body.alert_type || j.alert_type || 'UNKNOWN').toUpperCase();

  // TV_INGRESS_CLASSIFICATION_PATCH_20260505:
  // Some TradingView bar-close alerts intentionally use alert_type=HEARTBEAT to
  // keep the pipe warm, but they still carry market payload fields. Classify by
  // payload shape so monitors do not count real TV posts as internal-only pings.
  const _hasTicker = !!(body.ticker || body.symbol || body.sym || j.ticker || j.symbol || j.sym);
  const _hasMarketIntent = !!(
    body.execution || body.trade_action || body.direction || body.signal ||
    body.price || body.close || body.bias_score || body.bull_score || body.bear_score ||
    body.timeframe || body.interval || j.execution || j.trade_action || j.direction
  );
  const _isTvMarketPayload = _hasTicker && _hasMarketIntent;
  const _ingressSource = _isTvMarketPayload
    ? 'TRADINGVIEW_MARKET_ALERT'
    : (INTERNAL.has(alertType) ? 'INTERNAL_CONTROL' : 'EXTERNAL_WEBHOOK');
  body._ingress_source = _ingressSource;
  body._tv_payload_shape = _isTvMarketPayload ? 'ticker+market_fields' : 'control_or_unknown';
  body._original_alert_type = alertType;
  item.json._ingress_source = _ingressSource;
  item.json._tv_payload_shape = body._tv_payload_shape;

  // Internal invocations bypass auth (preserve existing behavior; classification
  // above lets monitors distinguish TV-like HEARTBEAT payloads without risking
  // signal loss from a sudden auth policy change).
  if (INTERNAL.has(alertType)) {
    out.push(promoteAuthenticatedPayload(item, body, query, headers, alertType, _ingressSource));
    continue;
  }

  // TV_AUTH_QUERY_SECRET_PATCH_20260504:
  // Accept the same expected secret from JSON body, flattened payload, query string, or header.
  // This supports TradingView setups where the passphrase is placed in the webhook URL:
  //   /webhook/tradingview-signal?_secret=<secret>
  // while still fail-closing when the secret is absent or wrong.
  const supplied = String(body._secret || j._secret || query._secret || headerSecret || '');
  if (!supplied || supplied !== expected) {
    // Throwing produces a node error visible to cron AUTH_FAILED detector and kills downstream execution.
    const detail = {
      reason: 'AUTH_FAILED',
      has_secret: !!supplied,
      secret_source: body._secret ? 'body' : (j._secret ? 'top_level' : (query._secret ? 'query' : (headerSecret ? 'header' : 'missing'))),
      alert_type: alertType,
      ticker: body.ticker || j.ticker || null
    };
    throw new Error('AUTH_FAILED: ' + JSON.stringify(detail));
  }
  out.push(promoteAuthenticatedPayload(item, body, query, headers, alertType, _ingressSource));
}
return out;

// Normalize Alpaca Events for Supabase
// QTP-BACKTEST-METADATA-PRESERVER v4.2.13
// Purpose: convert Alpaca order/close node outputs into explicit, idempotent
// Supabase logging events. Non-blocking. Trading logic untouched.
// Additive fix: preserve standardized backtest/enforcement fields in raw_payload
// so order_events/trade_log rows can be traced back to the same VC/audit decision.

function first(...vals) {
  for (const v of vals) {
    if (v !== undefined && v !== null && v !== '') return v;
  }
  return undefined;
}

function num(v, fallback = null) {
  if (v === undefined || v === null || v === '' || String(v).toUpperCase() === 'N/A') return fallback;
  const n = Number(String(v).replace('%', '').trim());
  return Number.isFinite(n) ? n : fallback;
}

function str(v, fallback = '') {
  const x = first(v, fallback);
  return x === undefined || x === null ? '' : String(x);
}

function upper(v, fallback = '') {
  return str(v, fallback).trim().toUpperCase();
}

function sideFromExecution(execution, statusSide) {
  const e = upper(execution || statusSide);
  if (['BUY', 'LONG'].includes(e)) return 'BUY';
  if (['SELL', 'SHORT'].includes(e)) return 'SELL';
  return e || 'UNKNOWN';
}

function isoNow() {
  return new Date().toISOString();
}

function stableHash(obj) {
  const s = JSON.stringify(obj || {});
  let h = 2166136261;
  for (let i = 0; i < s.length; i++) {
    h ^= s.charCodeAt(i);
    h = Math.imul(h, 16777619);
  }
  return (h >>> 0).toString(16).padStart(8, '0');
}

function backtestEnvelope(p) {
  const sample = num(first(
    p._backtest_sample_size,
    p.backtest_sample_size,
    p.backtest_sample,
    p.strat_total_trades,
    p.total_trades,
    p.bt_total_trades
  ), null);

  const pf = num(first(
    p._backtest_profit_factor,
    p.backtest_profit_factor,
    p.backtest_pf,
    p.strat_profit_factor,
    p.profit_factor,
    p.bt_profit_factor
  ), null);

  const win = num(first(
    p._backtest_win_rate,
    p.backtest_win_rate,
    p.strat_win_rate,
    p.win_rate,
    p.bt_win_rate
  ), null);

  const status = first(
    p._backtest_status,
    p.backtest_status,
    sample === null || pf === null ? 'NO_BACKTEST_DATA' :
      (sample >= 100 && pf >= 1.2 ? 'BACKTEST_DATA_OK' : 'WEAK_BACKTEST_DATA')
  );

  const validRaw = first(p._backtest_valid, p.backtest_valid);
  const valid = validRaw !== undefined
    ? (validRaw === true || String(validRaw).toLowerCase() === 'true')
    : (sample !== null && pf !== null && sample >= 100 && pf >= 1.2);

  const requiredRaw = first(p._backtest_required, p.backtest_required);
  const required = requiredRaw === true || String(requiredRaw).toLowerCase() === 'true';

  return {
    strat_total_trades: sample,
    strat_profit_factor: pf,
    strat_win_rate: win,
    _backtest_sample_size: sample,
    _backtest_profit_factor: pf,
    _backtest_win_rate: win,
    _backtest_status: status,
    _backtest_valid: valid,
    _backtest_required: required,
    _backtest_enforcement_action: first(p._backtest_enforcement_action, p.backtest_action, valid ? 'ALLOW' : 'BLOCK_OR_DOWNGRADE'),
    _backtest_enforcement_reason: first(p._backtest_enforcement_reason, p.backtest_reason, valid ? 'Backtest data passed minimum quality gate' : 'Missing or weak backtest data'),
    _backtest_entry_class: first(p._backtest_entry_class, p.backtest_entry_class, p.signal_type, p.momentum_type, 'UNKNOWN'),
    qtp_order_event_backtest_version: 'QTP_BACKTEST_METADATA_PRESERVER_v4.2.13_20260513'
  };
}

function baseRecord(p) {
  const symbol = upper(first(p.ticker, p.symbol, p.alpaca_close_ticker));
  const ts = first(p._signal_timestamp, p.timestamp, p.Timestamp, p.created_at, isoNow());
  const side = sideFromExecution(first(p.execution, p.side, p.alpaca_side, p.alpaca_signal_side));
  const status = upper(first(p.alpaca_status, p.alpaca_close_status, p.order_status, p.status), 'UNKNOWN');
  const qty = num(first(p.alpaca_close_qty, p.alpaca_qty, p.qty, p.quantity, p.order_qty, p.filled_qty, p.filled_quantity), null);
  const price = num(first(p.alpaca_fresh_price, p.alpaca_signal_price, p.price, p.avg_fill_price, p.alpaca_close_exit_price), null);
  const entryId = first(p.alpaca_entry_id, p.order_id, p.broker_order_id, p.id);
  const closeId = first(p.alpaca_close_order_id, p.alpaca_order_id, p.close_order_id);
  const orderId = first(entryId, closeId, `${symbol}_${ts}_${stableHash(p).slice(0, 8)}`);
  const bt = backtestEnvelope(p);

  return {
    source_system: 'n8n_alpaca',
    source_node: first(p.alpaca_close_status, p.alpaca_close_reason) !== undefined ? 'Alpaca Position Closer' : 'Alpaca Paper Trade',
    symbol,
    ticker: symbol,
    event_ts: ts,
    trade_ts: ts,
    snapshot_ts: ts,
    order_id: String(orderId),
    broker_order_id: String(orderId),
    account_id: str(first(p.account_id, p.alpaca_account_id), 'alpaca'),
    strategy_id: str(first(p.strategy_id, p.strategy, p.alert_type, p.momentum_type), 'quantum_pipeline'),
    strategy_name: str(first(p.strategy_name, p.momentum_type, p.alert_type), 'quantum_pipeline'),
    signal_id: str(first(p.signal_id, p.Shadow_ID, p.shadow_id), `${symbol}_${ts}`),
    side,
    order_type: str(first(p.order_type), 'market'),
    time_in_force: str(first(p.time_in_force), 'gtc'),
    order_status: status,
    trade_status: status,
    requested_quantity: qty,
    filled_quantity: num(first(p.filled_quantity, p.filled_qty), status === 'PENDING_NEW' || status === 'SUBMITTED' ? 0 : qty),
    quantity: qty,
    avg_fill_price: price,
    mark_price: price,
    notional: num(first(p.alpaca_notional, p.notional), qty !== null && price !== null ? Number((Math.abs(qty) * price).toFixed(6)) : null),
    stop_price: first(p.alpaca_stop_price, p.stop_price),
    limit_price: first(p.limit_price),
    rejection_reason: first(p.alpaca_reason, p.alpaca_error, p.alpaca_close_reason, p.alpaca_close_error),
    model_version: first(p._sm_version, p.model_version, p.parser_version),
    risk_check_status: first(p.risk_check_status, p._sm_quality_gate),
    raw_payload: { ...p, ...bt },
  };
}

function shouldWriteTrade(status) {
  const s = upper(status);
  return ['NEW', 'ACCEPTED', 'PENDING_NEW', 'SUBMITTED', 'FILLED', 'PARTIALLY_FILLED', 'CLOSED', 'DONE_FOR_DAY'].includes(s);
}

function shouldWriteSnapshot(status) {
  const s = upper(status);
  return ['PENDING_NEW', 'SUBMITTED', 'FILLED', 'PARTIALLY_FILLED', 'CLOSED'].includes(s);
}

const output = [];

for (const item of $input.all()) {
  const p = item.json || {};
  const base = baseRecord(p);
  if (!base.symbol) continue;

  const eventKind = first(p.alpaca_close_status, p.alpaca_close_reason) !== undefined ? 'close' : 'order';
  const status = upper(first(p.alpaca_status, p.alpaca_close_status), 'UNKNOWN');
  const hashSeed = `${base.symbol}|${base.event_ts}|${base.order_id}|${status}|${eventKind}`;

  output.push({
    json: {
      ...base,
      target_table: 'order_events',
      event_type: eventKind === 'close' ? 'position_close_event' : 'alpaca_order_event',
      order_status: status,
      remaining_quantity: null,
      idempotency_key: `alpaca:order_event:${hashSeed}:${stableHash(base.raw_payload)}`,
    },
  });

  if (shouldWriteTrade(status)) {
    output.push({
      json: {
        ...base,
        target_table: 'trade_log',
        event_type: eventKind === 'close' ? 'position_closed' : 'order_submitted',
        trade_id: `alpaca_trade_${base.order_id}`,
        trade_status: status,
        execution_venue: 'alpaca',
        liquidity_flag: 'unknown',
        gross_pnl: num(first(p.alpaca_close_unrealized_pl, p.gross_pnl, p.pnl), null),
        net_pnl: num(first(p.alpaca_close_unrealized_pl, p.net_pnl, p.pnl), null),
        realized_pnl: eventKind === 'close' ? num(first(p.alpaca_close_unrealized_pl, p.realized_pnl, p.pnl), null) : null,
        unrealized_pnl: eventKind === 'close' ? 0 : null,
        notes: first(p.alpaca_reason, p.alpaca_close_reason, p.comment),
        idempotency_key: `alpaca:trade_log:${hashSeed}:${stableHash(base.raw_payload)}`,
      },
    });
  }

  if (shouldWriteSnapshot(status)) {
    const qtyAfter = eventKind === 'close' && status === 'CLOSED' ? 0 : base.quantity;
    output.push({
      json: {
        ...base,
        target_table: 'portfolio_snapshot',
