// QTP_MTF_SHADOW_v1.1_20260601
// QTP_MTF_SHADOW_LT_VALUE_POSTHOC_SWEEP_v1_20260601
// Sibling node: writes a candidate MTF score (0.65·scalp + 0.35·swing) plus a
// LT-veto check alongside the legacy MTF decision. Pure observability — does
// NOT alter routing, scoring, broker behavior, or any downstream field.
//
// v1.1 changes (council mandate 2026-05-31, see qtp_reject_backtest_prereg v1.4-REVERTED):
// - Capture raw pre-threshold long_term tier score as shadow_lt_value (numeric|null)
//   to enable post-hoc 30/70 threshold sweeps without re-instrumenting.
// - LT veto and shadow_lt_value share _ltRaw — single source, cannot disagree.
// - Catch-path also writes shadow_lt_value: null. NULL distinguishes uncomputed
//   from genuine zero-signal.
//
// Output (appended to item.json, never replaces existing fields):
//   shadow_mtf_score        numeric|null      candidate score (0.65·scalp + 0.35·swing)
//   shadow_mtf_decision     string            SHADOW_PASS | SHADOW_BLOCK_SCORE | SHADOW_BLOCK_LT_VETO | SHADOW_ERROR
//   shadow_size_multiplier  numeric|null      clamp01((score - 55) / 45); logged only, never applied
//   shadow_lt_veto          boolean|null      true iff LT triggered the veto
//   shadow_lt_value         numeric|null      raw pre-threshold long_term tier score (v1.1 NEW)
//   shadow_engine_v         string            'QTP_MTF_SHADOW_v1.1_20260601'

const SHADOW_ENGINE_V = 'QTP_MTF_SHADOW_v1.1_20260601';
const SCORE_THRESHOLD = 55;
const SCALP_WEIGHT = 0.65;
const SWING_WEIGHT = 0.35;
const LT_VETO_LONG  = 30;  // LONG blocked if long_term < 30
const LT_VETO_SHORT = 70;  // SHORT blocked if long_term > 70

const results = [];

for (const item of items) {
  const d = item.json || {};
  try {
    // Parse mtf_tiers — may arrive as JSON string or object
    let tiers = d.mtf_tiers;
    if (typeof tiers === 'string') {
      try { tiers = JSON.parse(tiers); } catch (e) { tiers = {}; }
    }
    if (!tiers || typeof tiers !== 'object') tiers = {};

    // Tier scores
    const scalp  = Number(tiers && tiers.scalp     ? tiers.scalp.score     : NaN);
    const swing  = Number(tiers && tiers.swing     ? tiers.swing.score     : NaN);
    const _ltRaw = Number(tiers && tiers.long_term ? tiers.long_term.score : NaN);

    // v1.1: raw LT capture for post-hoc threshold sweeps.
    // Pre-threshold, NOT veto-clamped. Single source with the veto comparison below.
    const shadow_lt_value = Number.isFinite(_ltRaw) ? _ltRaw : null;

    // Side normalization
    const sideRaw = String(d.side || d.execution || d.signal || d.action || d.direction || '').toUpperCase();
    const isLong  = ['BUY', 'BULLISH', 'LONG'].indexOf(sideRaw) !== -1;
    const isShort = ['SELL', 'BEARISH', 'SHORT'].indexOf(sideRaw) !== -1;

    // Weighted score — requires both scalp + swing finite
    const haveScores = Number.isFinite(scalp) && Number.isFinite(swing);
    const shadow_mtf_score = haveScores ? (SCALP_WEIGHT * scalp + SWING_WEIGHT * swing) : null;

    // LT veto — shares _ltRaw with shadow_lt_value
    let shadow_lt_veto = false;
    if (Number.isFinite(_ltRaw)) {
      if (isLong  && _ltRaw < LT_VETO_LONG)  shadow_lt_veto = true;
      if (isShort && _ltRaw > LT_VETO_SHORT) shadow_lt_veto = true;
    }

    // Decision
    let shadow_mtf_decision;
    if (!haveScores) {
      shadow_mtf_decision = 'SHADOW_ERROR';
    } else if (shadow_lt_veto) {
      shadow_mtf_decision = 'SHADOW_BLOCK_LT_VETO';
    } else if (shadow_mtf_score >= SCORE_THRESHOLD) {
      shadow_mtf_decision = 'SHADOW_PASS';
    } else {
      shadow_mtf_decision = 'SHADOW_BLOCK_SCORE';
    }

    // Size multiplier — logged only, never applied
    let shadow_size_multiplier;
    if (!Number.isFinite(shadow_mtf_score)) {
      shadow_size_multiplier = null;
    } else {
      const raw = (shadow_mtf_score - SCORE_THRESHOLD) / 45;
      shadow_size_multiplier = Math.max(0, Math.min(1, raw));
    }

    // Append shadow fields. Never replace existing payload.
    results.push({
      json: Object.assign({}, d, {
        shadow_mtf_score: shadow_mtf_score,
        shadow_mtf_decision: shadow_mtf_decision,
        shadow_size_multiplier: shadow_size_multiplier,
        shadow_lt_veto: shadow_lt_veto,
        shadow_lt_value: shadow_lt_value,
        shadow_engine_v: SHADOW_ENGINE_V,
      }),
    });
  } catch (err) {
    // Pass-through on error — write SHADOW_ERROR sentinel, never break pipeline.
    // v1.1: catch path also writes shadow_lt_value: null.
    results.push({
      json: Object.assign({}, d, {
        shadow_mtf_score: null,
        shadow_mtf_decision: 'SHADOW_ERROR',
        shadow_size_multiplier: null,
        shadow_lt_veto: null,
        shadow_lt_value: null,
        shadow_engine_v: SHADOW_ENGINE_V,
        _shadow_engine_error: String((err && err.message) || err).slice(0, 240),
      }),
    });
  }
}

return results;

// QTP_BIAS_FILTER_DROP_SQL_BUILDER_v1.3_20260601 — observability-only, drop-branch
// v1.3: ADDITIVE — persists mtf_veto_leg (P0.1) + composite_opposition_count + composite_opposition_reasons.
//        mtf_veto_leg is NULL except for MTF_CONFLUENCE drops. composite_* populated whenever Bias Filter computed them.
// v1.2: persists blocked_stage (mirrors drop_reason) + bias_filter_exception_msg (from v5.12 try/catch).
//        Invariant: every drop-path row in exec_flow_audit gets blocked_stage = bias_filter_drop_reason.
// v1.1: persists optional _bias_filter_pass_subreason into bias_filter_drop_subreason column.
// Idempotent: targets the most recent matching exec_flow_audit row whose drop_reason is still NULL.
const out = [];
for (const it of items) {
  const j = it.json || {};
  const ticker = String(j.ticker || j.symbol || '').toUpperCase().replace(/'/g, "''").slice(0, 16);
  const side   = String(j.execution || j._sm_route || j.signal || '').toUpperCase().replace(/'/g, "''").slice(0, 8);
  const reason = String(j._bias_filter_pass_reason || 'UNKNOWN').replace(/'/g, "''").slice(0, 64);
  const subraw = j._bias_filter_pass_subreason;
  const subSql = (subraw === null || subraw === undefined || subraw === '')
      ? 'NULL'
      : `'${String(subraw).replace(/'/g, "''").slice(0, 64)}'`;
  // v1.2: blocked_stage mirrors drop_reason (drop-path truth column).
  // Special case 'UNKNOWN' → still write it so blocked_stage is never NULL when drop_reason is set
  // (invariant: bias_filter_drop_reason IS NOT NULL ⇒ blocked_stage IS NOT NULL AND <> 'NONE').
  const blockedStageSql = `'${reason}'`;
  // v1.2: bias_filter_exception_msg — only populated on EXCEPTION-path rows from v5.12 try/catch.
  // For non-EXCEPTION drops, write NULL (column stays NULL → "no exception" semantics).
  const excRaw = j._bias_filter_exception_msg;
  const exceptionMsgSql = (excRaw === null || excRaw === undefined || excRaw === '')
      ? 'NULL'
      : `'${String(excRaw).replace(/'/g, "''").slice(0, 240)}'`;
  // v1.3: mtf_veto_leg (P0.1) — NULL except on MTF_CONFLUENCE drops.
  const mtfVetoLegRaw = j._mtf_veto_leg;
  const mtfVetoLegSql = (mtfVetoLegRaw === null || mtfVetoLegRaw === undefined || mtfVetoLegRaw === '')
      ? 'NULL'
      : `'${String(mtfVetoLegRaw).replace(/'/g, "''").slice(0, 32)}'`;
  // v1.3: composite_opposition_count + composite_opposition_reasons — populated on every drop row.
  const compCntRaw = j._composite_opposition_count;
  const compCntSql = (compCntRaw === null || compCntRaw === undefined || compCntRaw === '')
      ? 'NULL'
      : String(Math.max(0, Math.min(7, Number(compCntRaw) | 0)));
  const compReasonsRaw = j._composite_opposition_reasons;
  const compReasonsSql = (compReasonsRaw === null || compReasonsRaw === undefined || compReasonsRaw === '')
      ? 'NULL'
      : `'${String(compReasonsRaw).replace(/'/g, "''").slice(0, 1024)}'`;
  if (!ticker || !side) continue;
  const sql = `
    WITH target AS (
      SELECT ctid FROM quantum.exec_flow_audit
      WHERE symbol = '${ticker}'
        AND side   = '${side}'
        AND ts >= now() - interval '3 minutes'
        AND bias_filter_drop_reason IS NULL
      ORDER BY ts DESC LIMIT 1
    )
    UPDATE quantum.exec_flow_audit
       SET bias_filter_drop_reason       = '${reason}',
           bias_filter_drop_subreason    = ${subSql},
           bias_filter_drop_at           = now(),
           blocked_stage                 = ${blockedStageSql},
           bias_filter_exception_msg     = ${exceptionMsgSql},
           mtf_veto_leg                  = ${mtfVetoLegSql},
           composite_opposition_count    = ${compCntSql},
           composite_opposition_reasons  = ${compReasonsSql}
     WHERE ctid IN (SELECT ctid FROM target)
    RETURNING ts, symbol, side, bias_filter_drop_reason, bias_filter_drop_subreason, blocked_stage, bias_filter_exception_msg, mtf_veto_leg, composite_opposition_count, composite_opposition_reasons;
  `.trim();
  out.push({ json: { ...j, __bias_drop_sql: sql } });
}
return out;

// PF_MARGIN Bypass Gate v1.0 - Option 2 PF_MARGIN paper bypass
// Reads upstream item.json (from QTP Bias Filter output) + flag row (from Flag Reader)
// Evaluates 13 conditions in EXACT brief order, fail-closed at first failure.
// Tightening 1: is_test_injection===true OR harness===true (legacy) marks signal as TEST.
// Tightening 2: ANY routed test signal MUST have is_dummy=true at insert time.
// C3 explicit: per architect d224664c, _bias_filter_pass must be true (NOT redundant — Splitter routes downstream of tap).
// LIVE path FAIL-CLOSED PANIC: not wired yet.

// Wiring (PATH C, Option α): QTP Bias Filter -> PF_MARGIN Flag Reader -> PF_MARGIN Bypass Gate (this node) -> Executor -> Trade Insert -> Telegram
// $input.first().json == flag row (from Flag Reader, the direct upstream postgres node).
// $('QTP Bias Filter') exposes the original signal item that originated this branch.
let flagRow = null;
try { flagRow = $input.first()?.json || null; } catch (_) {}

let j = {};
try { j = $('QTP Bias Filter').first()?.json || {}; } catch (_) { j = {}; }
if (!flagRow || !flagRow.flag_name) {
  return [{ json: {
    ...j,
    _pfm_routed: false,
    _pfm_route_mode: 'skip',
    _pfm_reason: 'flag_row_missing_fail_closed',
    _pfm_version: 'v1.0',
    _pfm_skip_at_condition: 0
  }}];
}

// ---------- helpers ----------
function num(v, d=0) { const n = Number(String(v ?? '').replace('%','').trim()); return Number.isFinite(n) ? n : d; }
function strU(v) { return String(v ?? '').trim().toUpperCase(); }
function boolish(v) {
  if (v === true) return true;
  if (v === false) return false;
  const s = String(v ?? '').trim().toLowerCase();
  return ['true','1','yes','y','on','pass','passed','allow'].includes(s);
}

const raw = (j.raw_payload && typeof j.raw_payload === 'object') ? j.raw_payload : {};

// ---------- test marker (Tightening 1) ----------
const is_test_injection = (raw.is_test_injection === true) || (raw.harness === true);
const has_legacy_harness_only = (raw.harness === true) && (raw.is_test_injection !== true);

// ---------- gate inputs: raw_payload.force_* overrides upstream ----------
function take(forceKey, ...upstreamFallbacks) {
  if (raw[forceKey] !== undefined && raw[forceKey] !== null) return raw[forceKey];
  for (const v of upstreamFallbacks) {
    if (v !== undefined && v !== null && String(v).trim() !== '') return v;
  }
  return undefined;
}

const det_score        = num(take('force_det_score', j.det_score, j.deterministic_score, j._mtf_deterministic_score, j.mtf_confluence_score), NaN);
const backtest_pf      = num(take('force_backtest_pf', j.backtest_pf, j._backtest_profit_factor), NaN);
const bias_pass        = (raw.force_bias !== undefined && raw.force_bias !== null)
                          ? (strU(raw.force_bias) === 'BIAS_PASS' || boolish(raw.force_bias))
                          : (j._bias_filter_pass === true);
const vc_in            = take('force_vc', j.vc_gate_decision, j._vc_decision, j.gate_decision);
const vc_pass          = strU(vc_in) === 'VC_PASS' || strU(vc_in) === 'PASS' || boolish(vc_in);
const risk_gate_in     = take('force_risk_gate_decision', j.risk_gate_decision);
const risk_gate_pass   = strU(risk_gate_in) === 'RISK_PASS';
const pause_guard_in   = take('force_pause_guard', j.pause_guard_pass, j.pause_status);
const pause_guard_pass = boolish(pause_guard_in) || strU(pause_guard_in) === 'PASS' || strU(pause_guard_in) === 'OK';
const spread_pct       = num(take('force_spread_pct', j.spread_pct, (j.spread_bps != null ? j.spread_bps/100 : null)), NaN);
const symbol           = strU(j.symbol || j.ticker || raw.ticker);
const side             = strU(j.side || raw.side);

// ---------- emit shape: defaults ----------
const out = {
  ...j,
  _pfm_routed: false,
  _pfm_route_mode: 'skip',
  _pfm_reason: '',
  _pfm_skip_at_condition: 0,
  _pfm_is_test_injection: is_test_injection,
  _pfm_has_legacy_harness_only: has_legacy_harness_only,
  _pfm_flag_value: flagRow.flag_value,
  _pfm_flag_enabled: flagRow.enabled === true,
  _pfm_symbol: symbol,
  _pfm_side: side,
  _pfm_det_score: det_score,
  _pfm_backtest_pf: backtest_pf,
  _pfm_bias_pass: bias_pass,
  _pfm_vc_pass: vc_pass,
  _pfm_risk_gate_pass: risk_gate_pass,
  _pfm_pause_guard_pass: pause_guard_pass,
  _pfm_spread_pct: spread_pct,
  _pfm_version: 'v1.0',
  _pfm_decided_at: new Date().toISOString()
};

function skip(condN, reason) {
  return [{ json: { ...out, _pfm_routed: false, _pfm_route_mode: 'skip', _pfm_reason: reason, _pfm_skip_at_condition: condN } }];
}

// ---------- 13 conditions (brief order) ----------

// C0: flag.enabled must be true (kill switch)
if (flagRow.enabled !== true) return skip(0, 'disabled_flag');

// C0a: halted_until in future ⇒ skip
if (flagRow.halted_until && new Date(flagRow.halted_until).getTime() > Date.now()) {
  return skip(0, 'halted:' + (flagRow.halt_reason || 'unknown'));
}

// C1: DET score in [65, 100)
if (!(det_score >= 65 && det_score < 100)) return skip(1, `det_score_out_of_range:${det_score}`);

// C2: backtest_pf in [1.00, 1.20)
if (!(backtest_pf >= 1.00 && backtest_pf < 1.20)) return skip(2, `pf_out_of_window:${backtest_pf}`);

// C3: bias_filter_pass === true (EXPLICIT — architect d224664c)
if (bias_pass !== true) return skip(3, 'bias_filter_not_pass');

// C4: VC pass
if (vc_pass !== true) return skip(4, 'vc_not_pass');

// C5: risk_gate_decision === 'RISK_PASS'
if (risk_gate_pass !== true) return skip(5, 'risk_gate_unavailable');

// C6: pause_guard pass
if (pause_guard_pass !== true) return skip(6, 'pause_guard_block');

// C7: spread_pct must be present and < 0.5%
if (!Number.isFinite(spread_pct) || !(spread_pct < 0.5)) return skip(7, `spread_too_wide:${spread_pct}`);

// C8: symbol present
if (!symbol) return skip(8, 'no_symbol');

// C9: side ∈ {BUY, SELL, LONG, SHORT}
if (!['BUY','SELL','LONG','SHORT'].includes(side)) return skip(9, `invalid_side:${side}`);

// C10: daily_trade_count < 2 (max 2/day)
if (Number(flagRow.daily_trade_count || 0) >= 2) return skip(10, 'daily_trade_cap_reached');

// C11: consecutive_losses < 2
if (Number(flagRow.consecutive_losses || 0) >= 2) return skip(11, 'consecutive_loss_halt');

// C12: daily_pnl_dollars > -5 (architect amendment: was -200)
if (Number(flagRow.daily_pnl_dollars || 0) <= -5) return skip(12, 'daily_dd_halt');

// C13: notional cap; raised $50 -> $1000 on 2026-06-29 (PO) for paper-canary fills. Executor sizes whole-share floor(cap/price). Still bounded: daily_trade_count<2, paper-only, T+60m sweep.
const NOTIONAL_CAP = 1000.0;

// ---------- ROUTING DECISION ----------
const fv = strU(flagRow.flag_value);
let route_mode = 'skip';
let mode_reason = '';

if (fv === 'OFF_AWAITING_DUMMY_QA' || fv === 'TESTS_PASSED_AWAITING_GO_LIVE') {
  // QA states — bypass enabled=true here is unusual but possible during Step C tests
  // Still treat as skip (these are NOT live values)
  route_mode = 'skip';
  mode_reason = `flag_value_not_live:${fv}`;
} else if (fv === 'QA_PASSED_AWAITING_GO_LIVE') {
  // Steps A, D, E (dry-run): write audit row, NO Alpaca call
  route_mode = 'dry_run';
} else if (fv === 'TEST_E2E_CANCEL_ONLY') {
  // Step F: submit-then-cancel real Alpaca paper order
  route_mode = 'test_cancel';
} else if (fv === 'PAPER_FILL_V1') {
  route_mode = 'paper_fill';
  mode_reason = 'routed_paper_fill_v1';
} else if (fv === 'LIVE') {
  // FAIL-CLOSED PANIC: LIVE path not wired (no exit handler). Route to Executor's panic branch so it logs + refuses, then skip.
  // We still set routed=true so the Executor sees it (and refuses). Trade Insert will NOT fire because Executor returns no executor_result on panic.
  route_mode = 'panic_live_not_wired';
  mode_reason = 'LIVE_branch_reached_but_exit_handler_unwired_failclosed';
} else {
  // Unknown flag_value → fail closed
  route_mode = 'skip';
  mode_reason = `unknown_flag_value:${fv}`;
}

// Tightening 1 audit: harness-only without is_test_injection is allowed but flagged
if (route_mode !== 'skip' && has_legacy_harness_only) {
  out._pfm_legacy_harness_warning = 'harness=true without is_test_injection=true — accepted as legacy alias';
}

// Build Alpaca payload skeleton (used by Executor for test_cancel only; dry_run ignores)
const alpaca_payload = {
  symbol: symbol,
  notional: String(NOTIONAL_CAP.toFixed(2)),
  side: (side === 'BUY' || side === 'LONG') ? 'buy' : 'sell',
  type: 'market',
  time_in_force: 'day',
  client_order_id: `EXP-PFM-${Date.now()}-${Math.random().toString(36).slice(2,8)}`
};

if (route_mode === 'skip') {
  return skip(13, mode_reason || 'flag_state_not_routable');
}

return [{ json: {
  ...out,
  _pfm_routed: true,
  _pfm_route_mode: route_mode,
  _pfm_reason: mode_reason || `routed_${route_mode}`,
  _pfm_alpaca_payload: alpaca_payload,
  _pfm_notional_cap: NOTIONAL_CAP
}}];

// PF_MARGIN Executor v1.0 - Option 2 PF_MARGIN paper bypass
// Inputs: $input.first().json = output of PF_MARGIN Bypass Gate
// Modes:
//   skip                  -> passthrough (no Alpaca, no insert downstream; Trade Insert SQL must no-op)
//   dry_run               -> NO Alpaca call. Build "executor_result" with intended order, no order_id, no fill.
//   test_cancel           -> Submit MARKET order via Alpaca paper API, then CANCEL within 5s. Record everything.
//   panic_live_not_wired  -> Log + emit panic marker. NO Alpaca call. NO insert.
// LIVE branch is intentionally absent: PANIC handled above. Tomorrow's PUT wires LIVE exit handler.

const j = $input.first()?.json || {};

function fail(reason, extra={}) {
  return [{ json: { ...j, _pfm_executor_status: 'fail', _pfm_executor_reason: reason, _pfm_executor_result: null, ...extra } }];
}

// Passthrough: if Bypass Gate already decided skip, just forward (Trade Insert handles no-op).
if (j._pfm_routed !== true) {
  return [{ json: { ...j, _pfm_executor_status: 'noop_skip', _pfm_executor_reason: j._pfm_reason || 'gate_skip', _pfm_executor_result: null } }];
}

const mode = String(j._pfm_route_mode || '').toLowerCase();
const symbol = String(j._pfm_symbol || '').toUpperCase();
const ap = j._pfm_alpaca_payload || {};
const is_test = j._pfm_is_test_injection === true;

// PANIC: LIVE path
if (mode === 'panic_live_not_wired') {
  console.error('[EXP-PFM][PANIC] LIVE branch reached but exit-handler not wired. Aborting. flag_value=' + j._pfm_flag_value);
  return [{ json: { ...j, _pfm_executor_status: 'panic_refuse', _pfm_executor_reason: 'LIVE_branch_unwired_refused', _pfm_executor_result: null } }];
}

// DRY_RUN: build executor_result without any Alpaca side effects
if (mode === 'dry_run') {
  const result = {
    mode: 'dry_run',
    intended_payload: ap,
    alpaca_order_id: null,
    alpaca_status: null,
    submission_intended_price: null,
    filled_avg_price: null,
    submission_ts: new Date().toISOString(),
    exit_reason: 'DRY_RUN_NO_ALPACA',
    notional_filled: 0,
    buying_power_delta: 0
  };
  return [{ json: { ...j, _pfm_executor_status: 'ok', _pfm_executor_reason: 'dry_run_no_alpaca_call', _pfm_executor_result: result } }];
}

// TEST_CANCEL (Step F): real Alpaca paper, submit then cancel
if (mode === 'test_cancel') {
  // Resolve credentials & base URL — mirror Alpaca Paper Trade pattern
  const _creds = $getWorkflowStaticData('global');
  const _credsStore = (_creds && _creds._credentials) || {};
  const ALPACA_KEY = $vars?.ALPACA_API_KEY || $vars?.ALPACA_KEY_ID || _credsStore.alpaca_api_key || '';
  const ALPACA_SEC = $vars?.ALPACA_SECRET_KEY || $vars?.ALPACA_SECRET || _credsStore.alpaca_secret_key || '';
  if (!ALPACA_KEY || !ALPACA_SEC) {
    return fail('alpaca_creds_missing_failclosed');
  }
  const BASE = $vars?.ALPACA_BASE_URL || _credsStore.alpaca_base || 'https://paper-api.alpaca.markets';
  if (!String(BASE).toLowerCase().includes('paper')) {
    return fail('alpaca_base_not_paper_endpoint_refused', { _pfm_executor_base: BASE });
  }
  const HDR = {
    'APCA-API-KEY-ID': ALPACA_KEY,
    'APCA-API-SECRET-KEY': ALPACA_SEC,
    'Content-Type': 'application/json'
  };

  // PRE-CHECK: capture buying_power baseline (architect ask)
  let baseline_buying_power = null;
  try {
    const acct = await $helpers.httpRequest({
      method: 'GET', url: BASE + '/v2/account', headers: HDR, json: true, timeout: 5000
    });
    baseline_buying_power = Number(acct?.buying_power ?? acct?.cash ?? NaN);
  } catch (e) {
    return fail('account_read_failed:' + (e.message || e).toString().slice(0,200));
  }

  // SUBMIT
  let order = null, order_err = null;
  const submission_ts = new Date().toISOString();
  try {
    order = await $helpers.httpRequest({
      method: 'POST', url: BASE + '/v2/orders', headers: HDR,
      body: ap, json: true, timeout: 8000
    });
  } catch (e) {
    order_err = (e.message || String(e)).slice(0, 400);
    return fail('alpaca_submit_failed:' + order_err, { _pfm_executor_baseline_buying_power: baseline_buying_power });
  }
  const order_id = order?.id || null;
  if (!order_id) return fail('alpaca_submit_no_order_id', { _pfm_executor_baseline_buying_power: baseline_buying_power, _pfm_executor_submit_response: order });

  // CANCEL immediately (within 5s requirement)
  const cancel_ts = new Date().toISOString();
  let cancel_status = 'unknown';
  let cancel_err = null;
  try {
    await $helpers.httpRequest({
      method: 'DELETE', url: BASE + '/v2/orders/' + encodeURIComponent(order_id), headers: HDR, json: true, timeout: 5000
    });
    cancel_status = 'requested';
  } catch (e) {
    cancel_err = (e.message || String(e)).slice(0,400);
    cancel_status = 'cancel_error:' + cancel_err;
  }

  // VERIFY: re-read order to confirm status
  let final_order = null;
  try {
    final_order = await $helpers.httpRequest({
      method: 'GET', url: BASE + '/v2/orders/' + encodeURIComponent(order_id), headers: HDR, json: true, timeout: 5000
    });
  } catch (_) {}

  // POST-CHECK: re-read buying_power
  let post_buying_power = null;
  try {
    const acct2 = await $helpers.httpRequest({
      method: 'GET', url: BASE + '/v2/account', headers: HDR, json: true, timeout: 5000
    });
    post_buying_power = Number(acct2?.buying_power ?? acct2?.cash ?? NaN);
  } catch (_) {}

  const buying_power_delta = (Number.isFinite(baseline_buying_power) && Number.isFinite(post_buying_power))
    ? Math.abs(post_buying_power - baseline_buying_power)
    : null;

  const result = {
    mode: 'test_cancel',
    intended_payload: ap,
    alpaca_order_id: order_id,
    alpaca_status: String(final_order?.status || order?.status || 'unknown'),
    cancel_requested_at: cancel_ts,
    cancel_status: cancel_status,
    submission_ts: submission_ts,
    submission_intended_price: null,  // market order, no intended limit; brief Q5: use filled_avg_price first
    filled_avg_price: final_order?.filled_avg_price != null ? Number(final_order.filled_avg_price) : null,
    exit_reason: 'TEST_CANCEL',
    notional_filled: Number(final_order?.filled_qty || 0) * Number(final_order?.filled_avg_price || 0),
    baseline_buying_power: baseline_buying_power,
    post_buying_power: post_buying_power,
    buying_power_delta: buying_power_delta,
    raw_submit_response: order,
    raw_final_order: final_order
  };

  // Architect ask: assert |delta| < $0.50
  if (buying_power_delta != null && buying_power_delta >= 0.50) {
    return [{ json: { ...j, _pfm_executor_status: 'warn', _pfm_executor_reason: 'buying_power_delta_exceeds_threshold:' + buying_power_delta.toFixed(4), _pfm_executor_result: result } }];
  }

  return [{ json: { ...j, _pfm_executor_status: 'ok', _pfm_executor_reason: 'submit_then_cancel_ok', _pfm_executor_result: result } }];
}

// PAPER_FILL_V1: submit a bounded WHOLE-SHARE market order and HOLD (no cancel). Exit via T+60m sweep.
//   Whole-share (not notional) because Alpaca rejects fractional SHORT sales; sized <= notional cap.
if (mode === 'paper_fill') {
  if (!symbol) return fail('empty_symbol_failclosed');
  const _creds = $getWorkflowStaticData('global');
  const _credsStore = (_creds && _creds._credentials) || {};
  const ALPACA_KEY = $vars?.ALPACA_API_KEY || $vars?.ALPACA_KEY_ID || _credsStore.alpaca_api_key || '';
  const ALPACA_SEC = $vars?.ALPACA_SECRET_KEY || $vars?.ALPACA_SECRET || _credsStore.alpaca_secret_key || '';
  if (!ALPACA_KEY || !ALPACA_SEC) return fail('alpaca_creds_missing_failclosed');
  const BASE = $vars?.ALPACA_BASE_URL || _credsStore.alpaca_base || 'https://paper-api.alpaca.markets';
  if (!String(BASE).toLowerCase().includes('paper')) {
    return fail('alpaca_base_not_paper_endpoint_refused', { _pfm_executor_base: BASE });
  }
  const HDR = { 'APCA-API-KEY-ID': ALPACA_KEY, 'APCA-API-SECRET-KEY': ALPACA_SEC, 'Content-Type': 'application/json' };
  const NOTIONAL_CAP = (Number(j._pfm_notional_cap) > 0) ? Number(j._pfm_notional_cap) : 50.0;
  const _sideRaw = String(j._pfm_side || '').toUpperCase();
  let sideLc;
  if (_sideRaw === 'BUY' || _sideRaw === 'LONG') sideLc = 'buy';
  else if (_sideRaw === 'SELL' || _sideRaw === 'SHORT') sideLc = 'sell';
  else return fail('invalid_side_failclosed:' + _sideRaw);
  // PRICE: latest trade (IEX free feed) to size whole shares
  let refPrice = null;
  try {
    const q = await $helpers.httpRequest({ method: 'GET', url: 'https://data.alpaca.markets/v2/stocks/' + encodeURIComponent(symbol) + '/trades/latest?feed=iex', headers: HDR, json: true, timeout: 5000 });
    refPrice = Number(q?.trade?.p ?? NaN);
  } catch (e) { return fail('price_fetch_failed:' + (e.message || e).toString().slice(0,200)); }
  if (!Number.isFinite(refPrice) || refPrice <= 0) return fail('price_unavailable_failclosed');
  const qty = Math.floor(NOTIONAL_CAP / refPrice);
  if (qty < 1) return [{ json: { ...j, _pfm_executor_status: 'noop_skip', _pfm_executor_reason: 'price_over_notional_cap:' + refPrice.toFixed(2), _pfm_executor_result: null } }];
  // baseline buying power
  let baseline_buying_power = null;
  try {
    const acct = await $helpers.httpRequest({ method: 'GET', url: BASE + '/v2/account', headers: HDR, json: true, timeout: 5000 });
    baseline_buying_power = Number(acct?.buying_power ?? acct?.cash ?? NaN);
  } catch (e) { return fail('account_read_failed:' + (e.message || e).toString().slice(0,200)); }
  // SUBMIT whole-share market order, then HOLD (no DELETE)
  const order_payload = { symbol: symbol, qty: String(qty), side: sideLc, type: 'market', time_in_force: 'day', client_order_id: 'EXP-PFM-FILL-' + Date.now() + '-' + Math.random().toString(36).slice(2,8) };
  const submission_ts = new Date().toISOString();
  let order = null;
  try {
    order = await $helpers.httpRequest({ method: 'POST', url: BASE + '/v2/orders', headers: HDR, body: order_payload, json: true, timeout: 8000 });
  } catch (e) { return fail('alpaca_paper_fill_submit_failed:' + (e.message || String(e)).slice(0,300), { _pfm_executor_baseline_buying_power: baseline_buying_power }); }
  const order_id = order?.id || null;
  if (!order_id) return fail('alpaca_paper_fill_no_order_id', { _pfm_executor_submit_response: order });
  // poll once for fill (NO cancel)
  let final_order = null;
  try { final_order = await $helpers.httpRequest({ method: 'GET', url: BASE + '/v2/orders/' + encodeURIComponent(order_id), headers: HDR, json: true, timeout: 5000 }); } catch (_) {}
  const filled_avg_price = (final_order?.filled_avg_price != null) ? Number(final_order.filled_avg_price) : null;
  const filled_qty = Number(final_order?.filled_qty || 0);
  const result = {
    mode: 'paper_fill', intended_payload: order_payload, ref_price: refPrice, qty: qty,
    alpaca_order_id: order_id, alpaca_status: String(final_order?.status || order?.status || 'unknown'),
    submission_ts: submission_ts, submission_intended_price: refPrice,
    filled_avg_price: filled_avg_price, exit_reason: 'HELD_AWAITING_EXIT',
    pending_fill: filled_qty < 1,
    notional_filled: (filled_qty > 0 ? filled_qty * Number(filled_avg_price || refPrice) : qty * refPrice),
    baseline_buying_power: baseline_buying_power, raw_submit_response: order, raw_final_order: final_order
  };
  return [{ json: { ...j, _pfm_executor_status: 'ok', _pfm_executor_reason: 'paper_fill_held', _pfm_executor_result: result } }];
}

// Unknown mode → fail closed
return fail('unknown_route_mode:' + mode);

// PF_MARGIN Trade SQL Builder v1.0 - Option 2 PF_MARGIN paper bypass
// Builds the INSERT + flag-counter UPDATE SQL string for the postgres node next.
// Tightening 2: is_dummy is constructed as a SQL CASE — true for any flag_value != 'LIVE'.
//                Bypass code cannot set is_dummy=false unless flag_value='LIVE'. Hard at INSERT site.
// Skip/no-op cases produce a benign SELECT that returns no insert.

const j = $input.first()?.json || {};
const res = j._pfm_executor_result || {};
const execStatus = j._pfm_executor_status || 'noop';
const routeMode  = j._pfm_route_mode || 'skip';
const flagValue  = j._pfm_flag_value || '';
const symbol     = j._pfm_symbol || '';
const side       = j._pfm_side || '';
const isTest     = j._pfm_is_test_injection === true;
const gateReason = j._pfm_reason || '';
const executorReason = j._pfm_executor_reason || '';
const detScore   = (j._pfm_det_score != null && Number.isFinite(j._pfm_det_score)) ? j._pfm_det_score : null;
const backtestPf = (j._pfm_backtest_pf != null && Number.isFinite(j._pfm_backtest_pf)) ? j._pfm_backtest_pf : null;
const entryPrice = (routeMode === 'dry_run')
  ? null
  : ((res.filled_avg_price != null) ? Number(res.filled_avg_price) : (res.submission_intended_price != null ? Number(res.submission_intended_price) : null));
const exitReason = res.exit_reason || null;
const notional   = (res.notional_filled != null) ? Number(res.notional_filled) : null;
const alpacaOrderId = res.alpaca_order_id || null;

const wouldInsert = (execStatus === 'ok' || execStatus === 'warn') && (routeMode === 'dry_run' || routeMode === 'test_cancel' || routeMode === 'paper_fill');

function sqlNum(v) { return (v != null && Number.isFinite(Number(v))) ? Number(v).toString() : 'NULL'; }
function sqlText(v) { return (v == null || v === '') ? 'NULL' : ("'" + String(v).replace(/'/g, "''") + "'"); }

if (!wouldInsert) {
  // No-insert path: emit a benign SELECT so the postgres node returns a row but inserts nothing.
  const sql = "SELECT NULL::uuid AS trade_id, " + sqlText(routeMode) + "::text AS route_mode, NULL::boolean AS is_dummy, NULL::text AS alpaca_order_id, NULL::int AS new_daily_trade_count, 'no_insert_skip'::text AS insert_status;";
  return [{ json: { ...j, _pfm_sql: sql, _pfm_insert_planned: false } }];
}

// Audit JSON: pack additional fields not in the table into raw_alpaca_response
const audit = {
  flag_value_at_decision: flagValue,
  route_mode: routeMode,
  gate_reason: gateReason,
  executor_status: execStatus,
  executor_reason: executorReason,
  is_test_injection: isTest,
  alpaca_order_id: alpacaOrderId,
  submission_intended_price: res.submission_intended_price ?? null,
  submission_ts: res.submission_ts ?? null,
  cancel_status: res.cancel_status ?? null,
  cancel_requested_at: res.cancel_requested_at ?? null,
  alpaca_status: res.alpaca_status ?? null,
  baseline_buying_power: res.baseline_buying_power ?? null,
  post_buying_power: res.post_buying_power ?? null,
  buying_power_delta: res.buying_power_delta ?? null,
  intended_payload: res.intended_payload ?? null,
  raw_submit_response: res.raw_submit_response ?? null,
  raw_final_order: res.raw_final_order ?? null,
  bypass_version: 'v1.0'
};
const auditJson = JSON.stringify(audit).replace(/'/g, "''");

const sql =
  "WITH ins AS (\n" +
  "  INSERT INTO quantum.experiment_paper_trades (\n" +
  "    exp_name, signal_ts, audit_row_ts, symbol, side, is_dummy,\n" +
  "    det_score, backtest_pf, entry_price, entry_ts,\n" +
  "    notional_dollars, exit_reason, raw_alpaca_response\n" +
  "  ) VALUES (\n" +
  "    'pf_margin_paper_bypass', now(), now(),\n" +
  "    " + sqlText(symbol) + ", " + sqlText(side) + ",\n" +
  "    CASE WHEN " + sqlText(flagValue) + " = 'LIVE' THEN false ELSE true END,\n" +
  "    " + sqlNum(detScore) + ", " + sqlNum(backtestPf) + ", " + sqlNum(entryPrice) + ", " + ((routeMode === 'dry_run') ? 'NULL' : 'now()') + ",\n" +
  "    " + sqlNum(notional) + ", " + sqlText(exitReason) + ", '" + auditJson + "'::jsonb\n" +
  "  ) RETURNING trade_id, is_dummy\n" +
  "),\n" +
  "upd AS (\n" +
  "  UPDATE quantum.experiment_flags\n" +
  "  SET daily_trade_count = daily_trade_count + 1, updated_at = now()\n" +
  "  WHERE flag_name = 'pf_margin_paper_bypass' AND EXISTS (SELECT 1 FROM ins)\n" +
  "  RETURNING daily_trade_count\n" +
  ")\n" +
  "SELECT (SELECT trade_id FROM ins LIMIT 1) AS trade_id, " +
  sqlText(routeMode) + "::text AS route_mode, " +
  "(SELECT is_dummy FROM ins LIMIT 1) AS is_dummy, " +
  sqlText(alpacaOrderId) + "::text AS alpaca_order_id, " +
  "(SELECT daily_trade_count FROM upd LIMIT 1) AS new_daily_trade_count, " +
  "'inserted'::text AS insert_status;";

return [{ json: { ...j, _pfm_sql: sql, _pfm_insert_planned: true } }];

// PF_MARGIN Telegram Notifier v1.0 - Option 2 PF_MARGIN paper bypass
// Tightening 1: any signal marked is_test_injection=true MUST send a [TEST] prefixed alert.
// Always fires (skip / dry_run / test_cancel / panic), so audit trail is complete.

const j = $input.first()?.json || {};
const insertRow = (function(){
  try { return $input.first()?.json || {}; } catch(_) { return {}; }
})();

// Read upstream gate decision (Bypass Gate output context)
let gateCtx = j;
try { gateCtx = $('PF_MARGIN Bypass Gate').first()?.json || j; } catch(_) {}
let execCtx = j;
try { execCtx = $('PF_MARGIN Executor').first()?.json || j; } catch(_) {}

const isTest = (gateCtx._pfm_is_test_injection === true) || (execCtx._pfm_is_test_injection === true);
const symbol = gateCtx._pfm_symbol || '';
const side = gateCtx._pfm_side || '';
const routeMode = gateCtx._pfm_route_mode || 'skip';
const flagValue = gateCtx._pfm_flag_value || '';
const skipCond = gateCtx._pfm_skip_at_condition;
const gateReason = gateCtx._pfm_reason || '';
const execStatus = execCtx._pfm_executor_status || 'noop';
const execReason = execCtx._pfm_executor_reason || '';
const res = execCtx._pfm_executor_result || {};
const tradeId = insertRow.trade_id || j.trade_id || null;
const newDailyCount = insertRow.new_daily_trade_count || j.new_daily_trade_count || null;
const insertStatus = insertRow.insert_status || j.insert_status || 'unknown';

// Notification policy: only fire Telegram when meaningful. Otherwise return passthrough (silent).
// Fire on: (a) test injections (is_test_injection=true) — visibility for QA, (b) any routed=true outcome, (c) panic_refuse.
// Do NOT fire on production-mode skip outcomes — they would spam every signal that fails any of the 13 conditions.
const shouldNotify =
  isTest === true ||
  execStatus === 'panic_refuse' ||
  (gateCtx._pfm_routed === true && routeMode !== 'skip');

if (!shouldNotify) {
  return [{ json: { ...j, _pfm_telegram_status: 'suppressed', _pfm_telegram_reason: 'production_skip_silent' } }];
}

// Build subject tag chain
let tag = '[EXP-PFM]';
if (routeMode === 'dry_run') tag += '[DRY_RUN]';
else if (routeMode === 'test_cancel') tag += '[TEST_CANCEL]';
else if (routeMode === 'panic_live_not_wired') tag += '[PANIC]';
else if (routeMode === 'skip') tag += '[SKIP]';

if (isTest) tag += '[TEST]';  // Tightening 1: explicit test marker

let title = '';
let body = '';

if (routeMode === 'skip') {
  title = `${tag} Signal skipped`;
  body = `<b>${symbol || '(no symbol)'} ${side || ''}</b>\n` +
         `Reason: <code>${gateReason}</code> (condition C${skipCond ?? '?'})\n` +
         `flag_value=<code>${flagValue}</code>`;
} else if (execStatus === 'panic_refuse') {
  title = `${tag} PANIC — LIVE branch unwired, refused`;
  body = `<b>${symbol || '?'} ${side || '?'}</b>\nflag_value=<code>${flagValue}</code>\n` +
         `Executor refused. Investigate immediately.`;
} else if (routeMode === 'dry_run') {
  title = `${tag} Dry-run audit row`;
  body = `<b>${symbol} ${side}</b> @ notional=$50.00\n` +
         `trade_id=<code>${tradeId || 'N/A'}</code>\n` +
         `daily_count=${newDailyCount ?? '?'}, insert=<code>${insertStatus}</code>\n` +
         `exit_reason=<code>${res.exit_reason || 'DRY_RUN_NO_ALPACA'}</code>`;
} else if (routeMode === 'test_cancel') {
  const bpDelta = (res.buying_power_delta != null) ? `$${Number(res.buying_power_delta).toFixed(4)}` : 'N/A';
  title = `${tag} Submit-then-cancel test`;
  body = `<b>${symbol} ${side}</b>\n` +
         `order_id=<code>${res.alpaca_order_id || 'N/A'}</code>\n` +
         `alpaca_status=<code>${res.alpaca_status || '?'}</code>\n` +
         `cancel_status=<code>${res.cancel_status || '?'}</code>\n` +
         `buying_power_delta=<code>${bpDelta}</code> (threshold $0.50)\n` +
         `trade_id=<code>${tradeId || 'N/A'}</code>, insert=<code>${insertStatus}</code>` +
         (execStatus === 'warn' ? `\n⚠️ <b>WARN:</b> ${execReason}` : '');
} else {
  title = `${tag} Unknown route_mode=${routeMode}`;
  body = `exec_status=${execStatus}, reason=${execReason}`;
}

const text = `${title}\n${body}`;

// Telegram credentials (mirror cron task pattern; reuse bot + chat_id)
const TG_BOT = 'REDACTED_TELEGRAM_BOT_TOKEN';
const TG_CHAT = 'REDACTED_CHAT_ID';

try {
  const resp = await $helpers.httpRequest({
    method: 'POST',
    url: `https://api.telegram.org/bot${TG_BOT}/sendMessage`,
    body: { chat_id: TG_CHAT, parse_mode: 'HTML', disable_web_page_preview: true, text: text },
    json: true,
    timeout: 6000
  });
  return [{ json: { ...j, _pfm_telegram_status: 'ok', _pfm_telegram_message_id: resp?.result?.message_id || null, _pfm_telegram_text: text } }];
} catch (e) {
  return [{ json: { ...j, _pfm_telegram_status: 'fail', _pfm_telegram_error: (e.message||String(e)).slice(0,400), _pfm_telegram_text: text } }];
}

// Merge Option B Flags v2.1 — wires Option B flags into the actual MTF gate decision.
//   v2.1 (2026-07-02): SCALP leg threshold 60 → SCALP_MIN 50, aligned with engine v7 retune (PO-auth).
//   (E2E sprint fc010fe2 Stage 3 enablement; supersedes v1.2 which only attached flags
//    as observability.) Backwards compatible: when flags are OFF / wrong value / not
//    paper, the original v6.2 final_mtf_confluence_decision is preserved byte-for-byte
//    (fail-closed). Original decision is always stamped to _optB_original_* for audit.
//
// Semantics (from experiment_flags notes):
//   mtf_profile_aware_composite_v1 (flag_value=ON_PAPER_PROFILE_AWARE_V1):
//     SCALP      -> scalp-tier-only PASS check (drop swing/long_term composite drag)
//     SWING      -> mean(scalp,swing) >= threshold AND neither scalp nor swing is BLOCK
//     LONG_TERM  -> unchanged (original v6.2 composite)
//   mtf_ai_advisory_paper_v1 (flag_value=ON_PAPER_ADVISORY_V1) AND paper_mode:
//     ai_mtf veto leg becomes advisory (logged in ai_mtf_advisory_engaged), NOT a hard
//     veto. Deterministic leg remains the gate.
//   Both legs fail-closed: disabled OR flag_value mismatch OR (advisory) not paper => no change.

const PROFILE_AWARE_VALUE = 'ON_PAPER_PROFILE_AWARE_V1';
const ADVISORY_VALUE = 'ON_PAPER_ADVISORY_V1';
const MTF_THRESHOLD = 60; // QTP_MTF_THRESHOLD_LOWER_v6.3_20260521 (Merge MTF AI Verdict uses 60)
const SCALP_MIN = 50; // QTP_MTF_REJECTBACKTEST_RETUNE_v7_20260702 (PO-auth): align Option B SCALP leg
                      // with engine v7 gate (scalp>=50). 28d reject-backtest: scalp tier is the only
                      // correctly-signed intraday predictor; the old scalp>=60 here re-blocked clean
                      // scalp 50-59 signals that passed the v7 engine gate (NVDA/TKO/GEV/ON 2026-07-02).

let sigItems = [];
let flagItems = [];
try { sigItems = $('QTP MTF Shadow Engine v1.1').all() || []; } catch (e) { sigItems = []; }
try { flagItems = $('QTP MTF Option B Flags').all() || []; } catch (e) { flagItems = []; }

if (!sigItems.length) {
  return [];
}

// Build flags map (fail-closed: missing = disabled)
const flagsMap = {
  mtf_profile_aware_composite_v1: { flag_value: null, enabled: false, source: 'default_missing' },
  mtf_ai_advisory_paper_v1:        { flag_value: null, enabled: false, source: 'default_missing' }
};
for (const fi of flagItems) {
  const j = fi.json || {};
  const name = j.flag_name;
  if (Object.prototype.hasOwnProperty.call(flagsMap, name)) {
    flagsMap[name] = {
      flag_value: j.flag_value != null ? j.flag_value : null,
      enabled:    j.enabled === true,
      source:     'db'
    };
  }
}

function num(v, d = 0) { const n = Number(String(v ?? '').replace('%', '').trim()); return Number.isFinite(n) ? n : d; }
function upper(v) { return String(v ?? '').trim().toUpperCase(); }

const pa = flagsMap.mtf_profile_aware_composite_v1;
const ai = flagsMap.mtf_ai_advisory_paper_v1;
const profileAwareEngaged = pa.enabled === true && upper(pa.flag_value) === PROFILE_AWARE_VALUE;
const aiAdvisoryFlagEngaged = ai.enabled === true && upper(ai.flag_value) === ADVISORY_VALUE;

return sigItems.map(si => {
  const j = { ...(si.json || {}) };

  // --- paper-mode detection (mirror of Bias Filter isPaperGated) ---
  const qtpMode = upper(j.qtp_deployment_mode);
  const qtpTradingEnv = upper(j.qtp_trading_env || j.trading_env);
  const alpacaEnv = upper(j.alpaca_env || j.alpaca_mode);
  const liveTradingAllowed = j.qtp_live_trading_allowed === true || String(j.qtp_live_trading_allowed || '').toLowerCase() === 'true';
  const isPaperGated =
    (qtpMode === 'PRODUCTION_PAPER_GATED' || qtpTradingEnv === 'PAPER' || alpacaEnv === 'PAPER') &&
    liveTradingAllowed === false;

  // --- always-attach flags map + observability ---
  j.optB_flags = flagsMap;
  j._optB_merge_ts = new Date().toISOString();
  j._optB_merge_version = 'v2.1';
  j._optB_merge_sig_count = sigItems.length;
  j._optB_merge_flag_count = flagItems.length;
  j._optB_profile_aware_engaged = profileAwareEngaged;
  j._optB_ai_advisory_flag_engaged = aiAdvisoryFlagEngaged;
  j._optB_paper_mode = isPaperGated;

  // Preserve the original v6.2 decision for audit/rollback comparison.
  const origFinalDecision = String(j.final_mtf_confluence_decision || '');
  const origFinalPass = j.final_mtf_confluence_pass === true;
  j._optB_original_final_mtf_decision = origFinalDecision || 'N/A';
  j._optB_original_final_mtf_pass = origFinalPass;

  // If neither leg engages, leave decision EXACTLY as upstream set it (fail-closed).
  const advisoryActive = aiAdvisoryFlagEngaged && isPaperGated;
  if (!profileAwareEngaged && !advisoryActive) {
    j._optB_decision_source = 'ORIGINAL_V6_2_FAILCLOSED';
    j.ai_mtf_advisory_engaged = false;
    return { json: j };
  }

  // --- recompute deterministic leg ---
  const profile = upper(j.mtf_target_profile || j.target_profile || j.profile || j.timeframe_profile || 'SCALP');
  const scalp = num(j.scalp_confluence_score);
  const swing = num(j.swing_confluence_score);
  const longTerm = num(j.long_term_confluence_score);
  const detScore = num(j.mtf_confluence_score);
  const detDecisionText = upper(j.mtf_confluence_decision);
  const origDetPass = detDecisionText === 'MTF_CONFLUENCE_PASS' && detScore >= MTF_THRESHOLD;

  let detPass = origDetPass;
  let detSource = 'ORIGINAL_COMPOSITE';
  if (profileAwareEngaged) {
    if (profile === 'SCALP') {
      // scalp-tier-only PASS: scalp tier alone must clear SCALP_MIN (v7); swing/long_term drag removed.
      detPass = scalp >= SCALP_MIN;
      detSource = 'PROFILE_AWARE_SCALP_TIER_ONLY_V7_50';
    } else if (profile === 'SWING') {
      // mean(scalp,swing) >= threshold AND no tier BLOCK on scalp/swing.
      const mean = (scalp + swing) / 2;
      const noBlock = scalp >= MTF_THRESHOLD && swing >= MTF_THRESHOLD;
      detPass = mean >= MTF_THRESHOLD && noBlock;
      detSource = 'PROFILE_AWARE_SWING_MEAN_NOBLOCK';
    } else {
      // LONG_TERM unchanged
      detPass = origDetPass;
      detSource = 'PROFILE_AWARE_LONG_TERM_UNCHANGED';
    }
  }

  // --- recompute AI leg (advisory demotion) ---
  const aiDecisionText = upper(j.ai_mtf_decision);
  const aiScore = num(j.ai_mtf_confluence_score);
  const origAiPass = aiDecisionText === 'PASS' && aiScore >= MTF_THRESHOLD;
  let aiLegGates = true;       // does AI leg still act as a hard gate?
  let aiAdvisoryEngaged = false;
  if (advisoryActive) {
    aiLegGates = false;        // AI veto demoted to advisory
    aiAdvisoryEngaged = true;
  }

  // --- final composite ---
  // Deterministic leg always gates. AI leg gates only when not demoted to advisory.
  const finalPass = aiLegGates ? (detPass && origAiPass) : detPass;

  j.ai_mtf_advisory_engaged = aiAdvisoryEngaged;
  j._optB_det_pass = detPass;
  j._optB_det_source = detSource;
  j._optB_ai_orig_pass = origAiPass;
  j._optB_ai_leg_gates = aiLegGates;
  j._optB_decision_source = 'OPTION_B_v2.1';

  j.final_mtf_confluence_pass = finalPass;
  j.final_mtf_confluence_decision = finalPass ? 'FINAL_MTF_CONFLUENCE_PASS' : 'FINAL_MTF_CONFLUENCE_BLOCK';

  // Keep blocked_stage / summary coherent with the recomputed decision.
  if (finalPass) {
    // If Option B newly passes a previously-blocked signal, clear the MTF block stamp
    // (only if it was the MTF stage that set it).
    if (upper(j.blocked_stage) === 'MTF_CONFLUENCE_BLOCK') {
      j.blocked_stage = 'NONE';
      j._optB_cleared_mtf_block = true;
    }
  } else if (!j.blocked_stage || upper(j.blocked_stage) === '' || upper(j.blocked_stage) === 'NONE') {
    j.blocked_stage = 'MTF_CONFLUENCE_BLOCK';
  }
  j.final_mtf_confluence_summary =
    `${j.final_mtf_confluence_decision} | optB=${j._optB_decision_source} | det_src=${detSource} | ` +
    `det_pass=${detPass} ai_gates=${aiLegGates} ai_orig_pass=${origAiPass} | ` +
    `profile=${profile} scalp=${scalp} swing=${swing} long_term=${longTerm} det=${detScore} ai=${aiScore} | ` +
    `was=${origFinalDecision || 'N/A'}`;

  return { json: j };
});

// QTP SKIP-Branch Exec Flow Audit Builder v1.0 (E2E sprint fc010fe2 Stage 1)
// Purpose: SSM-killed / FAST_ONLY-routed entries reach Route Fast Only out0 -> Alpaca
//   Position Closer WITHOUT ever writing quantum.exec_flow_audit. The FULL branch
//   writes audit via "QTP Early Exec Flow Audit Builder"; the SKIP branch was blind.
//   This node taps Route Fast Only out0 and writes an exec_flow_audit row that
//   ALWAYS carries kill_stage_attribution (+ signal_id / idempotency_key / gate_lineage)
//   so v_qtp_e2e_live can surface which kill switch bound each killed organic signal.
// Pattern parity: mirrors the Early Audit Builder esc()/num()/bool() helpers and the
//   d._skip_exec_flow_audit_sql -> Prepare -> Postgres chain (INSERT ... SELECT, no
//   trailing semicolon; the Prepare node appends "; SELECT 'INSERTED' ...").
// Column list is the SAME 27-column tuple the Early Audit Builder writes, so both
//   branches produce schema-compatible exec_flow_audit rows.

const d = $json || {};

function esc(v) {
  if (v === undefined || v === null) return 'NULL';
  return "'" + String(v).replace(/'/g, "''").slice(0, 20000) + "'";
}
function num(v) {
  const n = Number(v);
  return Number.isFinite(n) ? String(n) : 'NULL';
}
function bool(v) {
  if (v === true) return 'TRUE';
  if (v === false) return 'FALSE';
  return 'NULL';
}
function clean(v, fallback = 'N/A') {
  if (v === undefined || v === null || v === '') return fallback;
  const s = String(v).replace(/\s+/g, ' ').trim();
  return s ? s.slice(0, 240) : fallback;
}
function upper(v, fallback = 'N/A') {
  return clean(v, fallback).toUpperCase();
}
function score(v) {
  const n = Number(String(v ?? '').replace('%', '').trim());
  return Number.isFinite(n) ? n : null;
}
function jsonClean(v, fallback = {}) {
  try {
    if (v === undefined || v === null || v === '') return fallback;
    if (typeof v === 'object') return v;
    return JSON.parse(String(v));
  } catch (e) {
    return fallback;
  }
}
function pickFirst(...vals) {
  for (const v of vals) {
    if (v !== undefined && v !== null && String(v).trim() !== '') return v;
  }
  return '';
}

const symbol = String(d.symbol || d.ticker || d.sym || d.asset || 'UNKNOWN').toUpperCase();
const side = String(d.side || d.execution || d.signal || d.action || d.direction || 'UNKNOWN').toUpperCase();

// VC scores (carried on the killed item if present; else NULL)
const vcLiveLegacy = d.vc_live_legacy ?? d.live_vc_score ?? d._vc_score_legacy ?? d._vc_score ?? null;
const vcLiveV2 = d.vc_live_v2 ?? d.live_vc_score_v2 ?? d._vc_score ?? null;
const vcShadow = d.vc_shadow ?? d._vc_shadow_scanner_score ?? d.shadow_vc_score ?? null;
const vcDelta = d.vc_delta ?? d._vc_parity_delta ?? d._vc_shadow_scanner_delta ?? null;

// SSM attribution (H1/H3). These are the values the SKIP branch exists to capture.
const ssmAction = upper(d._sm_action || d.ssm_action || d.signal_state_action || 'SKIP', 'SKIP');
const ssmReason = clean(d._sm_reason || d.ssm_reason || d.signal_state_reason || d.reason || 'N/A', 'N/A');
const ssmRoute = upper(d._sm_route || 'FAST_ONLY', 'FAST_ONLY');

// kill_stage_attribution: SSM stamps _sm_kill_stage_attribution when a kill switch
//   binds. On the SKIP branch a bound kill switch is the EXPECTED cause, so if SSM
//   left it null we fall back to a deterministic SSM_<route> marker rather than NULL,
//   guaranteeing v_qtp_e2e_live always shows a kill switch for killed entries.
const killStage = clean(
  pickFirst(
    d._sm_kill_stage_attribution,
    d.kill_stage_attribution,
    d._kill_stage_attribution,
    d.blocked_stage,
    d._blocked_stage
  ),
  `SSM_${ssmRoute}`
);

// H1 correlation keys (same source fields the Early Audit Builder reads)
const _h1SignalId = d._sm_signal_id || d.signal_id || null;
const _h1IdempotencyKey = d._sm_idempotency_key || d._sm_signal_id || d.idempotency_key || null;
const _h1GateLineage = (() => {
  const gl = d._sm_gate_lineage;
  if (gl === undefined || gl === null) return null;
  try { return (typeof gl === 'string') ? gl : JSON.stringify(gl); } catch (e) { return null; }
})();

// MTF context if carried (usually present from the confluence engine before SSM)
const mtfScore = score(pickFirst(d.mtf_confluence_score, d.ai_mtf_confluence_score));
const mtfDecision = clean(pickFirst(d.final_mtf_confluence_decision, d.mtf_confluence_decision), 'N/A');
const mtfTiers = jsonClean(pickFirst(d.mtf_tiers), {});
const timeframeHorizon = clean(pickFirst(d.timeframe_horizon, d.timeframe_profile), 'N/A');

// Shadow context if carried
const shadowScore = pickFirst(d.shadow_mtf_score);
const shadowDecision = pickFirst(d.shadow_mtf_decision);
const shadowSizeMult = pickFirst(d.shadow_size_multiplier);
const shadowLtVeto = (d.shadow_lt_veto ?? null);
const shadowEngineV = pickFirst(d.shadow_engine_v);
const shadowLtValue = pickFirst(d.shadow_lt_value);

const execId = ($execution && $execution.id) ? String($execution.id).slice(0, 12) : 'no-exec-id';
const inputKeys = Object.keys(d).slice(0, 18).join(',');

const auditBuilderVersion = 'QTP_SKIP_BRANCH_AUDIT_BUILDER_v1.0_E2E_fc010fe2_20260617';
const parserVersion = d.parser_version || d.vc_score_parser_version || d._vc_score_parser_version || auditBuilderVersion;

// On the SKIP branch the killed entry is, by definition, not allowed through:
//   gate_decision summarises why; risk/pause stay NULL (never evaluated on SKIP).
const gateDecisionParts = [
  `branch=SKIP_FAST_ONLY`,
  `sm_route=${ssmRoute}`, `sm_action=${ssmAction}`, `sm_reason=${ssmReason}`,
  `kill_stage_attribution=${killStage}`,
  `vc_v2=${vcLiveV2 ?? 'N/A'}`, `vc_legacy=${vcLiveLegacy ?? 'N/A'}`,
  `vc_shadow=${vcShadow ?? 'N/A'}`, `vc_delta=${vcDelta ?? 'N/A'}`,
  `mtf_confluence_score=${mtfScore ?? 'N/A'}`, `final_mtf_confluence_decision=${mtfDecision}`,
  `timeframe_horizon=${timeframeHorizon}`,
  `audit_builder_v=${auditBuilderVersion}`,
  `exec_id=${execId}`, `keys=${inputKeys}`
];
const gateDecision = gateDecisionParts.filter(Boolean).join(' | ').slice(0, 20000);

// risk_gate_decision / risk_status NULL on SKIP (Late Patcher leaves them; no risk eval).
const risk_gate_decision = null;
const risk_status_struct = null;
const pause_guard_decision = clean(d._pause_guard_decision, 'PAUSE_N/A');
const pause_status = clean(d._pause_status_struct, 'N/A');

d._skip_exec_flow_audit_sql = `INSERT INTO quantum.exec_flow_audit
(ts, symbol, side, vc_live_legacy, vc_live_v2, vc_shadow, vc_delta, gate_decision, parser_version,
 risk_gate_decision, risk_status, pause_guard_decision, pause_status,
 timeframe_horizon, mtf_tiers, mtf_confluence_score, final_mtf_confluence_decision,
 shadow_mtf_score, shadow_mtf_decision, shadow_size_multiplier, shadow_lt_veto, shadow_engine_v, shadow_lt_value,
 signal_id, idempotency_key, gate_lineage, kill_stage_attribution)
SELECT
  CURRENT_TIMESTAMP,
  ${esc(symbol)},
  ${esc(side)},
  ${num(vcLiveLegacy)},
  ${num(vcLiveV2)},
  ${num(vcShadow)},
  ${num(vcDelta)},
  ${esc(gateDecision)},
  ${esc(parserVersion)},
  ${esc(risk_gate_decision)},
  ${esc(risk_status_struct)},
  ${esc(pause_guard_decision)},
  ${esc(pause_status)},
  ${esc(timeframeHorizon)},
  ${esc(JSON.stringify(mtfTiers))}::jsonb,
  ${num(mtfScore)},
  ${esc(mtfDecision)},
  ${shadowScore === '' || shadowScore == null ? 'NULL' : num(shadowScore)},
  ${esc(shadowDecision || 'SHADOW_NA')},
  ${shadowSizeMult === '' || shadowSizeMult == null ? 'NULL' : num(shadowSizeMult)},
  ${bool(shadowLtVeto === '' ? null : shadowLtVeto)},
  ${esc(shadowEngineV || null)},
  ${shadowLtValue === '' || shadowLtValue == null ? 'NULL' : num(shadowLtValue)},
  ${esc(_h1SignalId)},
  ${esc(_h1IdempotencyKey)},
  ${_h1GateLineage == null ? 'NULL' : esc(_h1GateLineage) + '::jsonb'},
  ${esc(killStage)}`;

d._skip_exec_flow_audit_gate_decision_preview = gateDecision;
d._skip_exec_flow_audit_builder_version = auditBuilderVersion;
d._skip_exec_flow_audit_kill_stage_attribution = killStage;
return [{ json: d }];

// QTP Supabase SKIP-Branch Exec Flow Audit Insert prep v1.0 (E2E fc010fe2 Stage 1)
const d = ($input.first() && $input.first().json) || $json || {};
const statement = d._skip_exec_flow_audit_sql;
const sql = statement
  ? `${statement}; SELECT 'INSERTED' AS skip_exec_flow_audit_status;`
  : `SELECT 'SKIPPED_NO_SQL' AS skip_exec_flow_audit_status;`;
return [{ json: { ...d, __supabase_skip_exec_sql: sql, _skip_exec_flow_audit_version: 'QTP-SKIP-AUDIT_SUPABASE_v1.0_20260617' } }];

// QTP Ingress Guard Logger — log-only, parallel tap. NEVER throws, NEVER affects signal flow.
try {
  const items = $input.all();
  const item = (items && items[0]) ? items[0] : { json: {} };
  const j = item.json || {};
  const body = (j.body && typeof j.body === 'object') ? j.body : j;
  const headers = (j.headers && typeof j.headers === 'object') ? j.headers : {};

  const callerIp = headers['cf-connecting-ip']
    || headers['x-real-ip']
    || ((headers['x-forwarded-for'] || '').split(',')[0] || '').trim()
    || null;
  const bodyBytes = parseInt(headers['content-length']) || null;
  const cfRay = headers['cf-ray'] || null;
  const qtpSource = (body && body.qtp_source) ? body.qtp_source : null;
  const alertType = (body && body.alert_type) ? body.alert_type : null;
  const symbolCount = (body && (body.ticker || body.symbol)) ? 1 : null;

  const sq = (v) => (v === null || v === undefined) ? 'NULL' : ("'" + String(v).replace(/'/g, "''") + "'");
  const ni = (v) => (v === null || v === undefined || isNaN(v)) ? 'NULL' : String(parseInt(v));

  const sql = 'INSERT INTO quantum.webhook_ingress_log '
    + '(caller_ip, body_bytes, symbol_count, qtp_source, alert_type, cf_ray, note) VALUES ('
    + sq(callerIp) + ', '
    + ni(bodyBytes) + ', '
    + ni(symbolCount) + ', '
    + sq(qtpSource) + ', '
    + sq(alertType) + ', '
    + sq(cfRay) + ', '
    + sq('ingress_tap_v1') + ')';

  return [{ json: { _ig_sql: sql } }];
} catch (e) {
  return [{ json: { _ig_sql: null, note: 'ingress_logger_error' } }];
}
